```swift
import SwiftUI
import UIKit   // or AppKit on macOS

struct ContentView: View {
    var body: some View {
        VStack {
            Text("Hello, world!")
                .font(.largeTitle)
            Image(systemName: "star.fill")
                .foregroundColor(.yellow)
                .font(.system(size: 80))
        }
    }
}

func snapshot(of view: some View) -> UIImage? {
    // Create a renderer for the view
    let renderer = ImageRenderer(content: view)
    // Optionally set the desired size or scale
    renderer.scale = UIScreen.main.scale
    renderer.proposedSize = .init(width: 300, height: 300) // or .unspecified to use intrinsic size
    // Render to UIImage
    return renderer.uiImage
}

// Usage
if let bitmap = snapshot(of: ContentView()) {
    // `bitmap` is a UIImage you can share, save, etc.
    // For example, present a UIActivityViewController:
    let activity = UIActivityViewController(activityItems: [bitmap], applicationActivities: nil)
    // present `activity` from a view controller
}
```

